+/// Run the E2E pipeline for all fixtures.
+#[must_use]
+pub fn run_e2e_pipeline_all(
+    policy: RewritePolicy,
+    rules: &[RewriteRule],
+) -> Vec<E2ePipelineReport> {
+    all_fixtures()
